# MDM golden record management and survivorship
from dataclasses import dataclass, field
from typing import List, Optional, Dict, Any
from datetime import datetime, timezone
from enum import Enum

class DataAuthority(Enum):
    TIER_1 = 1  # Most authoritative
    TIER_2 = 2
    TIER_3 = 3  # Least authoritative

@dataclass
class SourceRecord:
    source_system: str
    source_id: str
    attributes: Dict[str, Any]
    authority_tier: DataAuthority
    last_updated: datetime

@dataclass
class GoldenRecord:
    entity_id: str
    entity_type: str
    attributes: Dict[str, Any]
    source_ids: Dict[str, str]
    survivorship_applied: Dict[str, str]
    version: int
    created_at: datetime
    updated_at: datetime

    def to_rag_document(self) -> Dict:
        return {
            "id": f"golden:{self.entity_id}:v{self.version}",
            "entity_id": self.entity_id,
            "entity_type": self.entity_type,
            "content": self._build_content_string(),
            "metadata": {
                "entity_id": self.entity_id,
                "golden_record_version": self.version,
                "updated_at": self.updated_at.isoformat(),
            }
        }

    def _build_content_string(self) -> str:
        lines = [f"Entity: {self.entity_type} | ID: {self.entity_id}"]
        for attr, value in self.attributes.items():
            lines.append(f"{attr}: {value}")
        return "\n".join(lines)

def apply_survivorship_rules(
    source_records: List[SourceRecord],
    attribute_authority: Dict[str, str],
) -> tuple:
    merged = {}
    survivorship_log = {}
    by_source = {r.source_system: r for r in source_records}

    all_attributes = set()
    for rec in source_records:
        all_attributes.update(rec.attributes.keys())

    for attr in all_attributes:
        preferred_source = attribute_authority.get(attr)
        if preferred_source and preferred_source in by_source:
            source_rec = by_source[preferred_source]
            if attr in source_rec.attributes:
                merged[attr] = source_rec.attributes[attr]
                survivorship_log[attr] = preferred_source
                continue
        sorted_recs = sorted(source_records, key=lambda r: r.authority_tier.value)
        for rec in sorted_recs:
            if attr in rec.attributes and rec.attributes[attr] is not None:
                merged[attr] = rec.attributes[attr]
                survivorship_log[attr] = rec.source_system
                break

    return merged, survivorship_log

# Example
now = datetime.now(timezone.utc)
source_records = [
    SourceRecord("erp", "ERP-456",
                 {"price": 189.99, "sku": "WGT-PRO-001", "inventory_status": "in_stock"},
                 DataAuthority.TIER_1, now),
    SourceRecord("crm", "CRM-789",
                 {"name": "Acme Widget Pro", "price": 199.99, "category": "hardware"},
                 DataAuthority.TIER_2, now),
    SourceRecord("marketing", "MKT-123",
                 {"name": "Widget Pro", "description": "Professional-grade widget."},
                 DataAuthority.TIER_3, now),
]

attribute_authority = {
    "price": "erp",
    "name": "crm",
    "description": "marketing",
    "sku": "erp",
    "category": "crm",
}

merged, log = apply_survivorship_rules(source_records, attribute_authority)
print("Merged:", merged)
# {"price": 189.99, "sku": "WGT-PRO-001", "name": "Acme Widget Pro", ...}
